mapper.select:
select count(1)
from cook_checkins
where user_id = #{userId}
  and checkin_date between #{startDate} and #{endDate}
  and deleted_at is null

mapper.update:
update cook_checkins
set deleted_at = current_timestamp,
    updated_at = current_timestamp
where id = #{id}
  and user_id = #{userId}
  and deleted_at is null
